import { AppSettingsErrorDetails } from './app-settings-error-details';
/**
 * Error object for an incomplete response
 */
export interface AppSettingsErrorIncomplete {
    /**
     * The HTTP status code
     */
    code?: number;
    /**
     * The error message
     */
    message: string;
    /**
     * The error details
     */
    details?: AppSettingsErrorDetails;
}
